import{c as e,Q as t,j as s,m as n}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"音视频工程系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/00-写作计划.md","filePath":"mediaTechLearning/00-写作计划.md","lastUpdated":1780887690000}'),i={name:"mediaTechLearning/00-写作计划.md"};function l(p,a,d,r,o,h){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="音视频工程系列写作计划" tabindex="-1">音视频工程系列写作计划 <a class="header-anchor" href="#音视频工程系列写作计划" aria-label="Permalink to &quot;音视频工程系列写作计划&quot;">​</a></h1><blockquote><p>这个系列不是&quot;FFmpeg 命令大全&quot;,也不是&quot;WebRTC API 速查&quot;。目标是把音视频工程里最容易混的几层拆开:采集、编码、封装、传输、播放、实时通话、直播、录制、转码、排障。</p><p>一句话:<strong>音视频工程 = 把连续的声音和画面压成可传输的数据,再在另一端按时间重新还原出来</strong>。难点不在&quot;能播&quot;,难点在延迟、卡顿、同步、兼容、带宽、成本和故障定位。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>四层结构,从本地文件一路走到实时通信:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础模型(声音 / 图像 / 时间轴 / 码率)</span></span>
<span class="line"><span>   -&gt; 文件与点播(容器 / 编码 / FFmpeg / HLS / 播放器)</span></span>
<span class="line"><span>   -&gt; 实时通信(WebRTC / SDP / ICE / RTP / SFU)</span></span>
<span class="line"><span>   -&gt; 生产工程(直播 / 录制 / 质量评估 / CDN / 成本 / 排障)</span></span></code></pre></div><p>不重复 networkLearning 已经讲过的网络基础,也不重复前端系列里浏览器 API 的泛讲。这里只关心音视频链路自己的问题:为什么同一个 MP4 有的浏览器不能播、为什么 WebRTC 本地通了线上不通、为什么直播延迟从 3 秒变成 30 秒、为什么转码机器 CPU 打满、为什么声音和画面对不上。</p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-基础心智-01-06" tabindex="-1">第一层:基础心智(01-06) <a class="header-anchor" href="#第一层-基础心智-01-06" aria-label="Permalink to &quot;第一层:基础心智(01-06)&quot;">​</a></h3><ul><li>[x] 01 音视频工程总览与心智</li><li>[x] 02 声音和图像怎么变成数据</li><li>[x] 03 采样率、帧率、码率、分辨率</li><li>[x] 04 容器格式:MP4 / FLV / MKV / WebM</li><li>[x] 05 编码格式:H.264 / H.265 / VP9 / AV1 / AAC / Opus</li><li>[x] 06 GOP、I/P/B 帧、关键帧</li></ul><h3 id="第二层-ffmpeg-与点播-07-15" tabindex="-1">第二层:FFmpeg 与点播(07-15) <a class="header-anchor" href="#第二层-ffmpeg-与点播-07-15" aria-label="Permalink to &quot;第二层:FFmpeg 与点播(07-15)&quot;">​</a></h3><ul><li>[x] 07 FFmpeg 心智模型</li><li>[x] 08 ffmpeg / ffprobe 常用命令</li><li>[x] 09 转码、转封装、裁剪、抽帧、水印</li><li>[x] 10 HLS 与 DASH 点播</li><li>[x] 11 M3U8、TS、fMP4 与分片</li><li>[x] 12 播放器原理与缓冲策略</li><li>[x] 13 浏览器 Media API</li><li>[x] 14 MediaRecorder 与本地录制</li><li>[x] 15 Web Audio API 入门</li></ul><h3 id="第三层-webrtc-实时通信-16-24" tabindex="-1">第三层:WebRTC 实时通信(16-24) <a class="header-anchor" href="#第三层-webrtc-实时通信-16-24" aria-label="Permalink to &quot;第三层:WebRTC 实时通信(16-24)&quot;">​</a></h3><ul><li>[x] 16 WebRTC 总览</li><li>[x] 17 SDP 与 Offer / Answer</li><li>[x] 18 ICE、STUN、TURN</li><li>[x] 19 RTP / RTCP</li><li>[x] 20 音视频采集、Track 与 MediaStream</li><li>[x] 21 DataChannel</li><li>[x] 22 一对一通话实战</li><li>[x] 23 多人会议架构:Mesh / SFU / MCU</li><li>[x] 24 SFU 心智:mediasoup / LiveKit / Janus</li></ul><h3 id="第四层-生产工程-25-30" tabindex="-1">第四层:生产工程(25-30) <a class="header-anchor" href="#第四层-生产工程-25-30" aria-label="Permalink to &quot;第四层:生产工程(25-30)&quot;">​</a></h3><ul><li>[x] 25 屏幕共享、录制与回放</li><li>[x] 26 直播系统:RTMP / SRT / WebRTC / HLS</li><li>[x] 27 低延迟直播</li><li>[x] 28 音视频质量评估与排障</li><li>[x] 29 带宽、CDN、存储与成本</li><li>[x] 30 音视频工程的未来</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>TCP / UDP / TLS / QUIC</td><td>networkLearning ✅</td><td>不重复协议基础,只讲音视频传输怎么用</td></tr><tr><td>直播系统架构</td><td>systemDesign/20 ✅</td><td>本系列补媒体协议、编码、播放器和低延迟细节</td></tr><tr><td>浏览器基础 API</td><td>webLearning ✅</td><td>只讲 Media / WebRTC / 播放器相关 API</td></tr><tr><td>移动端相机和权限</td><td>androidNative / iosNative ✅</td><td>不展开平台 UI,只讲采集、编码、推流和兼容</td></tr><tr><td>对象存储 / CDN / 成本</td><td>cloudBasics / backendLearning ✅</td><td>只讲音视频文件和直播流的特殊成本模型</td></tr></tbody></table><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-06 是&quot;看懂任何音视频问题&quot;的地基</span></span>
<span class="line"><span>07-15 是&quot;能处理文件和点播&quot;的核心</span></span>
<span class="line"><span>16-24 是&quot;能做实时通话和会议&quot;的核心</span></span>
<span class="line"><span>25-30 是&quot;上线后不被卡顿、延迟、账单打爆&quot;的工程化部分</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 24 篇,你应该能解释清楚一对一 WebRTC 通话从 <code>getUserMedia</code> 到远端出画面中间发生了什么,并且知道 TURN、SDP、ICE、RTP、SFU 各自解决哪一段问题。</p><hr><h2 id="完结-2026-06-08" tabindex="-1">完结(2026/06/08) <a class="header-anchor" href="#完结-2026-06-08" aria-label="Permalink to &quot;完结(2026/06/08)&quot;">​</a></h2><p>30 篇主线完成。下一步不要继续堆概念,应该做一个项目闭环:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>小型视频会议 + 录制回放系统</span></span>
<span class="line"><span>  WebRTC 一对一</span></span>
<span class="line"><span>  -&gt; TURN 兜底</span></span>
<span class="line"><span>  -&gt; SFU 多人房间</span></span>
<span class="line"><span>  -&gt; 屏幕共享</span></span>
<span class="line"><span>  -&gt; 服务端录制</span></span>
<span class="line"><span>  -&gt; FFmpeg 转码</span></span>
<span class="line"><span>  -&gt; HLS 回放</span></span>
<span class="line"><span>  -&gt; 质量指标面板</span></span></code></pre></div>`,28)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
